import{_ as i,o as a,c as l,ag as t}from"./chunks/framework.CAXxHpAX.js";const s=JSON.parse('{"title":"CherryStudio 配置指南","description":"","frontmatter":{},"headers":[],"relativePath":"apps/cherry-studio.md","filePath":"apps/cherry-studio.md"}'),d={name:"apps/cherry-studio.md"};function o(r,e,h,u,n,c){return a(),l("div",null,[...e[0]||(e[0]=[t('<h1 id="cherrystudio-配置指南" tabindex="-1">CherryStudio 配置指南 <a class="header-anchor" href="#cherrystudio-配置指南" aria-label="Permalink to &quot;CherryStudio 配置指南&quot;">​</a></h1><p>全能的 AI 助手桌面客户端</p><p>官方网站： <a href="https://www.cherry-ai.com/" target="_blank" rel="noreferrer">https://www.cherry-ai.com/</a> 下载地址： <a href="https://www.cherry-ai.com/download" target="_blank" rel="noreferrer">https://www.cherry-ai.com/download</a></p><p>📋 简介</p><p>CherryStudio 是一款功能强大的 AI 助手桌面应用，支持多种主流 AI 模型（Claude、Gemini、GPT 等），为开发者和用户提供统一的 AI 交互界面。本教程将指导你如何配置 CherryStudio 接入 IkunCode 平台。</p><h2 id="功能特点" tabindex="-1">功能特点 <a class="header-anchor" href="#功能特点" aria-label="Permalink to &quot;功能特点&quot;">​</a></h2><p>CherryStudio 提供以下强大功能：</p><ul><li>✅ 丰富功能：对话管理、模型切换、参数调整等</li><li>✅ 本地优先：数据存储在本地，保护隐私</li><li>✅ 跨平台：支持 Windows、macOS、Linux</li><li>✅ 自定义 API：支持接入自定义 API 提供商</li><li>✅ 统一界面：一个应用管理所有 AI 服务</li><li>✅ 多模型支持：支持 Claude、Gemini、GPT 等主流 AI 模型</li></ul><h2 id="安装步骤" tabindex="-1">安装步骤 <a class="header-anchor" href="#安装步骤" aria-label="Permalink to &quot;安装步骤&quot;">​</a></h2><h3 id="第一步-下载安装-cherrystudio" tabindex="-1">第一步：下载安装 CherryStudio <a class="header-anchor" href="#第一步-下载安装-cherrystudio" aria-label="Permalink to &quot;第一步：下载安装 CherryStudio&quot;">​</a></h3><p>访问 CherryStudio 下载页面</p><p>根据你的操作系统选择对应的安装包：</p><ul><li>Linux：下载 <code>.AppImage</code> 或 <code>.deb</code> 包</li><li>macOS：下载 <code>.dmg</code> 镜像文件</li><li>Windows：下载 <code>.exe</code> 安装程序</li></ul><p>下载完成后，按照系统提示完成安装</p><p>💡 macOS 用户注意</p><p>如果提示&quot;无法打开，因为它来自身份不明的开发者&quot;，请在系统偏好设置 → 安全性与隐私中允许打开。</p><h3 id="第二步-获取-ikuncode-api-key" tabindex="-1">第二步：获取 IkunCode API Key <a class="header-anchor" href="#第二步-获取-ikuncode-api-key" aria-label="Permalink to &quot;第二步：获取 IkunCode API Key&quot;">​</a></h3><p>在配置 CherryStudio 之前，需要先从 IkunCode 平台获取 API Key：</p><p>根据需要创建对应的令牌组：</p><ul><li>Gemini 模型：选择 gemini 分组</li><li>Claude 模型：选择 只允许逆向分组</li></ul><p>保存生成的 API Key</p><p>📋 配置快速参考</p><table tabindex="0"><thead><tr><th>模型</th><th>提供商类型</th><th>API 地址</th><th>令牌组</th></tr></thead><tbody><tr><td>Claude</td><td><code>Anthropic</code></td><td><code>https://api.ikuncode.cc/v1/messages</code></td><td>只允许逆向分组</td></tr><tr><td>Gemini</td><td><code>Gemini</code></td><td><code>https://api.ikuncode.cc/v1beta/models</code></td><td>gemini 分组</td></tr></tbody></table><h2 id="配置-claude-模型" tabindex="-1">配置 Claude 模型 <a class="header-anchor" href="#配置-claude-模型" aria-label="Permalink to &quot;配置 Claude 模型&quot;">​</a></h2><h3 id="第一步-进入设置页面" tabindex="-1">第一步：进入设置页面 <a class="header-anchor" href="#第一步-进入设置页面" aria-label="Permalink to &quot;第一步：进入设置页面&quot;">​</a></h3><ol><li>打开 CherryStudio 应用</li><li>点击左下角的「设置」或「偏好设置」</li><li>选择「模型配置」或「API 配置」选项</li></ol><h3 id="第二步-选择-claude-模型类型" tabindex="-1">第二步：选择 Claude 模型类型 <a class="header-anchor" href="#第二步-选择-claude-模型类型" aria-label="Permalink to &quot;第二步：选择 Claude 模型类型&quot;">​</a></h3><p>在模型列表中选择你需要的 Claude 模型：</p><ul><li>Claude 3.5 Haiku：速度快，适合简单任务</li><li>Claude Sonnet 4.5：<code>claude-sonnet-4-5-20250929</code> - 最新版本，适合日常编码和对话（推荐）</li><li>Claude Opus 4.5：<code>claude-opus-4-5-20251101</code> - 最强性能，适合复杂任务</li></ul><p>💡 提示</p><p>具体可用的模型取决于你在 IkunCode 平台创建的令牌组权限。</p><h3 id="第三步-配置-claude-api" tabindex="-1">第三步：配置 Claude API <a class="header-anchor" href="#第三步-配置-claude-api" aria-label="Permalink to &quot;第三步：配置 Claude API&quot;">​</a></h3><p>在 Claude 配置界面中填写以下信息：</p><p>配置参数：</p><ul><li>提供商类型：选择 <code>Anthropic</code></li><li>API 地址：<code>https://api.ikuncode.cc/v1/messages</code></li><li>API Key：粘贴你从 IkunCode 控制台获取的 Claude API Key</li><li>模型名称：输入上一步选择的模型名称（如 <code>claude-sonnet-4-5-20250929</code>）</li></ul><h2 id="配置-gemini-模型" tabindex="-1">配置 Gemini 模型 <a class="header-anchor" href="#配置-gemini-模型" aria-label="Permalink to &quot;配置 Gemini 模型&quot;">​</a></h2><h3 id="第一步-选择-gemini-模型类型" tabindex="-1">第一步：选择 Gemini 模型类型 <a class="header-anchor" href="#第一步-选择-gemini-模型类型" aria-label="Permalink to &quot;第一步：选择 Gemini 模型类型&quot;">​</a></h3><p>在模型列表中选择你需要的 Gemini 模型：</p><ul><li>Gemini 2.0 Flash：快速响应，适合简单对话</li><li>Gemini 3 Flash Preview：<code>gemini-3-flash-preview</code> - 最新版本，速度快，性能优秀（推荐）</li><li>Gemini 3 Pro Preview：<code>gemini-3-pro-preview</code> - 高性能，适合复杂任务</li></ul><p>⚠️ 注意</p><ul><li>确保你在 IkunCode 平台创建了对应的令牌组</li><li>Gemini 和 Claude 需要使用不同的 API Key（不同的令牌组）</li></ul><h3 id="第二步-配置-gemini-api" tabindex="-1">第二步：配置 Gemini API <a class="header-anchor" href="#第二步-配置-gemini-api" aria-label="Permalink to &quot;第二步：配置 Gemini API&quot;">​</a></h3><p>在 Gemini 配置界面中填写以下信息：</p><p>配置参数：</p><ul><li>提供商类型：选择 <code>Gemini</code></li><li>API 地址：<code>https://api.ikuncode.cc/v1beta/models</code></li><li>API Key：粘贴你从 IkunCode 控制台获取的 Gemini API Key</li><li>模型名称：输入上一步选择的模型名称（如 <code>gemini-3-flash-preview</code>）</li></ul><h2 id="开始使用" tabindex="-1">开始使用 <a class="header-anchor" href="#开始使用" aria-label="Permalink to &quot;开始使用&quot;">​</a></h2><h3 id="创建新对话" tabindex="-1">创建新对话 <a class="header-anchor" href="#创建新对话" aria-label="Permalink to &quot;创建新对话&quot;">​</a></h3><ol><li>点击「新建对话」或「New Chat」按钮</li><li>在模型选择器中选择已配置的模型</li><li>开始与 AI 对话</li></ol><h3 id="切换模型" tabindex="-1">切换模型 <a class="header-anchor" href="#切换模型" aria-label="Permalink to &quot;切换模型&quot;">​</a></h3><p>在对话过程中，你可以随时切换不同的模型：</p><ol><li>点击顶部的模型选择器</li><li>选择其他已配置的模型</li><li>继续对话（上下文可能会保留或重置，取决于应用设置）</li></ol><h3 id="调整参数" tabindex="-1">调整参数 <a class="header-anchor" href="#调整参数" aria-label="Permalink to &quot;调整参数&quot;">​</a></h3><p>CherryStudio 通常支持调整以下参数：</p><ul><li>Temperature（温度）：控制回复的随机性（0-1）</li><li>Max Tokens（最大令牌数）：控制回复长度</li><li>Top P：控制采样范围</li></ul><p>💡 参数建议</p><ul><li>编程任务：Temperature 0.2-0.5（更准确）</li><li>日常对话：Temperature 0.5-0.7（平衡）</li><li>创意写作：Temperature 0.7-0.9（更有创意）</li></ul><h2 id="最佳实践" tabindex="-1">最佳实践 <a class="header-anchor" href="#最佳实践" aria-label="Permalink to &quot;最佳实践&quot;">​</a></h2><h3 id="_1-合理选择模型" tabindex="-1">1. 合理选择模型 <a class="header-anchor" href="#_1-合理选择模型" aria-label="Permalink to &quot;1. 合理选择模型&quot;">​</a></h3><p>不同任务使用不同模型：</p><ul><li>代码编写：Claude Sonnet 4.5（<code>claude-sonnet-4-5-20250929</code>）</li><li>复杂推理：Claude Opus 4.5（<code>claude-opus-4-5-20251101</code>）</li><li>快速对话：Gemini 3 Flash Preview（<code>gemini-3-flash-preview</code>）</li><li>多模态任务：Gemini 3 Pro Preview（支持图片）</li></ul><h3 id="_2-管理-api-使用" tabindex="-1">2. 管理 API 使用 <a class="header-anchor" href="#_2-管理-api-使用" aria-label="Permalink to &quot;2. 管理 API 使用&quot;">​</a></h3><ul><li>定期检查 IkunCode 控制台的余额</li><li>为不同用途创建不同的 API Key</li><li>避免在公共场合泄露 API Key</li></ul><h3 id="_3-优化对话体验" tabindex="-1">3. 优化对话体验 <a class="header-anchor" href="#_3-优化对话体验" aria-label="Permalink to &quot;3. 优化对话体验&quot;">​</a></h3><ul><li>使用清晰的提示词</li><li>合理设置上下文长度</li><li>善用对话历史管理功能</li></ul><h2 id="与其他客户端的对比" tabindex="-1">与其他客户端的对比 <a class="header-anchor" href="#与其他客户端的对比" aria-label="Permalink to &quot;与其他客户端的对比&quot;">​</a></h2><table tabindex="0"><thead><tr><th>特性</th><th>CherryStudio</th><th>Alma</th><th>Hapi</th></tr></thead><tbody><tr><td>界面类型</td><td>桌面应用</td><td>桌面应用</td><td>Web/PWA</td></tr><tr><td>多模型支持</td><td>✅</td><td>✅</td><td>✅</td></tr><tr><td>代码编辑</td><td>部分支持</td><td>✅</td><td>✅</td></tr><tr><td>终端集成</td><td>❌</td><td>✅</td><td>✅</td></tr><tr><td>远程访问</td><td>❌</td><td>❌</td><td>✅</td></tr><tr><td>学习曲线</td><td>低</td><td>中</td><td>中</td></tr></tbody></table><p>选择建议：</p><ul><li>纯对话需求：CherryStudio（界面简洁，易上手）</li><li>编程开发：Alma 或 Hapi（功能更强大）</li><li>远程控制：Hapi（独有功能）</li></ul><h2 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h2><h3 id="提示-api-key-无效" tabindex="-1">提示 API Key 无效？ <a class="header-anchor" href="#提示-api-key-无效" aria-label="Permalink to &quot;提示 API Key 无效？&quot;">​</a></h3><p>可能原因：</p><ul><li>API Key 输入错误</li><li>令牌组选择错误（只允许逆向分组的 Key 不能用于 Gemini）</li><li>余额不足</li></ul><p>解决方法：</p><ol><li>检查 API Key 是否完整复制</li><li>确认在 IkunCode 控制台创建了正确的令牌组（Claude 用 只允许逆向分组，Gemini 用 gemini 分组）</li><li>查看账户余额是否充足</li></ol><h3 id="模型列表为空" tabindex="-1">模型列表为空？ <a class="header-anchor" href="#模型列表为空" aria-label="Permalink to &quot;模型列表为空？&quot;">​</a></h3><p>可能原因：</p><ul><li>API Key 权限不足</li><li>网络连接问题</li><li>Base URL 配置错误</li></ul><p>解决方法：</p><ol><li>确认 Claude 的 API 地址为 <code>https://api.ikuncode.cc/v1/messages</code></li><li>确认 Gemini 的 API 地址为 <code>https://api.ikuncode.cc/v1beta/models</code></li><li>检查网络连接</li><li>重新获取 API Key 并确保令牌组权限正确</li></ol><h3 id="对话响应速度慢" tabindex="-1">对话响应速度慢？ <a class="header-anchor" href="#对话响应速度慢" aria-label="Permalink to &quot;对话响应速度慢？&quot;">​</a></h3><p>可能原因：</p><ul><li>网络延迟</li><li>选择的模型较大</li><li>上下文过长</li></ul><p>解决方法：</p><ol><li>检查网络连接质量</li><li>尝试使用更快的模型（如 Gemini Flash）</li><li>清理或减少对话历史</li></ol><h3 id="如何同时使用多个模型" tabindex="-1">如何同时使用多个模型？ <a class="header-anchor" href="#如何同时使用多个模型" aria-label="Permalink to &quot;如何同时使用多个模型？&quot;">​</a></h3><p>在 CherryStudio 中：</p><ol><li>分别配置不同的模型提供商</li><li>可以创建多个对话窗口，每个使用不同模型</li><li>在新建对话时选择对应的模型</li></ol><h3 id="更多问题" tabindex="-1">更多问题 <a class="header-anchor" href="#更多问题" aria-label="Permalink to &quot;更多问题&quot;">​</a></h3><p>请查看：</p><ul><li>CherryStudio 官方文档</li><li>IkunCode FAQ</li><li>IkunCode 控制台</li><li>售后支持</li></ul><h2 id="完成" tabindex="-1">完成 <a class="header-anchor" href="#完成" aria-label="Permalink to &quot;完成&quot;">​</a></h2><p>🎉 配置完成！现在你可以使用 CherryStudio 愉快地与 AI 对话了！</p><p>记住以下要点：</p><ul><li>✅ 不同模型使用不同的 API Key（不同令牌组）</li><li>✅ Claude API 地址：<code>https://api.ikuncode.cc/v1/messages</code></li><li>✅ Gemini API 地址：<code>https://api.ikuncode.cc/v1beta/models</code></li><li>✅ 根据任务选择合适的模型</li><li>✅ 定期检查 IkunCode 控制台的余额</li><li>✅ 妥善保管你的 API Key</li></ul><hr><p>相关教程：</p><ul><li>IkunCode 控制台</li><li><a href="/apps/hapi">Hapi 远程控制</a></li><li><a href="/apps/alma">Alma 客户端配置</a></li></ul>',97)])])}const m=i(d,[["render",o]]);export{s as __pageData,m as default};
